import ReactPlayer from 'react-player/youtube'

export default function Videos(props) {
    const videos = useSelector((s) => s.Library.publicVideos)
    const navigate = useNavigate()
    const dispatch = useDispatch()
    const { showConfirmationModal } = useConfirmationModalContext()
    const onChangeSelection = (workout) => {
        let existIndex = props?.selectedWorkout?.findIndex(
            (i) => i._id == workout._id
        )
        let arr = [...props.selectedWorkout]
        if (existIndex > -1) {
            arr.splice(existIndex, 1)
        } else {
            arr.push({
                ...workout,
                media:workout.href,
                type:"youtube"
            })
        }

        props.setSelectedWorkout(arr)
    }
    const delettheVideo = (id) => {
        showConfirmationModal(
            'Are you sure?',
            `You are going to delete this video`,
            'Delete'
        ).then((res) => {
            dispatch(
                deleteVideo({
                    _id: id,
                    savedToLibrary: false,
                })
            )
        })
    }
    return (
        <Box
            height={videos.length == 0 ? '100%' : 'auto'}
            display={videos.length == 0 ? 'flex' : 'block'}
            flexDirection={'column'}
            alignItems={'flex-start'}
        >
        
            {videos.length == 0 ? (
                <Box
                    flexGrow={1}
                    width={'100%'}
                    flexDirection={'column'}
                    display={'flex'}
                    alignItems={'center'}
                    justifyContent={'center'}
                >
                    <Typography align="center" color={'grey.600'}>
                        No public videos! <br />
                       
                    </Typography>
                </Box>
            ) : (
                videos?.map((i, index) => (
                    <VideoCard
                        title={i.title || 'unamed'}
                        id={i._id}
                        url={i.href}
                        onChangeSelection={() => onChangeSelection(i)}
                        checked={
                            props?.selectedWorkout?.find(
                                (vi) => vi._id == i._id
                            )
                                ? true
                                : false
                        }
                       
                        slectionMode={props?.slectionMode}
                        selectedWorkout={props?.selectedWorkout}
                        setSelectedWorkout={props?.setSelectedWorkout}
                    />
                ))
            )}
        </Box>
    )
}

const VideoCard = ({
    title,
    url,
    onClick,
    onChangeSelection,
    checked,
    slectionMode
 
}) => {
    const [open, setOpen] = React.useState(false);
    
    const handleOpen = () => setOpen(true);
    const handleClose = () => setOpen(false);
    
    return (
        <>
        <Dialog
            open={open}
            onClose={handleClose}
            maxWidth="lg"
        
            fullWidth
        >
            <Box sx={{ bgcolor: 'background.paper', p: 2 }}>
                <Stack direction="row" justifyContent="space-between" alignItems="center" mb={2}>
                    <Typography variant="h6">{title}</Typography>
                    <IconButton onClick={handleClose}>
                        <Iconify icon="eva:close-fill" />
                    </IconButton>
                </Stack>
                <Box sx={{ position: 'relative', paddingTop: '56.25%' }}>
                    <ReactPlayer
                        url={url}
                        width="100%"
                        height="100%"
                        style={{ position: 'absolute', top: 0, left: 0 }}
                       
                        playing
                    />
                </Box>
            </Box>
        </Dialog>
        <Box py={2}>
            <Stack
                direction={'row'}
                justifyContent={'space-between'}
                
            >
                <Box display={'flex'} alignItems={'center'}>
                    <Box
                        bgcolor={'#f0f0f0'}
                        borderRadius={1}
                        width={100}
                        height={65}
                        mr={1}
                        sx={{ overflow: 'hidden' }}
                        onClick={handleOpen}
                    >
                        <ImageWithFallback
                            //onClick={props.onClick}
                            variant="rounded"
                            style={{
                                width: '100%',
                                height: '100%',
                                objectFit: 'cover',
                            }}
                            src={
                                getYoutubeVideoTHumbnail(url) ||
                                '/images/instructor/exerciseImage.png'
                            }
                        />
                    </Box>
                    <Typography onClick={handleOpen} sx={{ textTransform: 'capitalize' }}>
                        {title}
                    </Typography>
                </Box>
                {slectionMode && (
                    <Checkbox
                        color="primary"
                        checked={checked}
                        onChange={onChangeSelection}
                    />
                )
            }
            </Stack>
           
        </Box>
        </>
    )
}
